code.python:
def fib(n, memo={}):
    if n <= 1: return n
    if n not in memo:
        memo[n] = fib(n-1, memo) + fib(n-2, memo)
    return memo[n]

code.javascript:
function fib(n, memo = {}) {
  if (n <= 1) return n;
  if (!(n in memo)) {
    memo[n] = fib(n-1, memo) + fib(n-2, memo);
  }
  return memo[n];
}

code.java:
int fib(int n, Map<Integer,Integer> memo) {
    if (n <= 1) return n;
    if (!memo.containsKey(n)) {
        memo.put(n, fib(n-1,memo) + fib(n-2,memo));
    }
    return memo.get(n);
}

code.cpp:
int fib(int n, unordered_map<int,int>& memo) {
    if (n <= 1) return n;
    if (!memo.count(n)) {
        memo[n] = fib(n-1,memo) + fib(n-2,memo);
    }
    return memo[n];
}

code.javascript:
function fib(n) {
  if (n <= 1) return n;
  const dp = new Array(n + 1).fill(0);
  dp[1] = 1;
  for (let i = 2; i <= n; i++) {
    dp[i] = dp[i-1] + dp[i-2];
  }
  return dp[n];
}

